VALUES
  ('fire-eq-tech-moex-02140', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依乾粉滅火設備設置規定，下列敘述何者正確？', '["加壓式乾粉滅火設備應設壓力調整裝置，可調整壓力至每平方公分二十五公斤以下", "加壓式乾粉滅火設備，其定壓動作裝置設於控制中心", "加壓式乾粉滅火設備，啟動裝置動作後，儲存容器壓力達設定壓力百分之八十時，應使放出閥開啟", "蓄壓式乾粉滅火設備應設置以藍色表示使用壓力範圍之指示壓力表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02141', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '消防搶救上之必要設備中，連結送水管之送水口設置，下列敘述何者錯誤？', '["送水口為雙口形，接裝口徑六十三公厘陰式快速接頭", "距基地地面之高度在一公尺以下零點五公尺以上", "標明連結送水管送水口字樣", "送水口在其附近便於檢查確認處，裝設測試用出水口"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02142', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '有關室內消防栓之規定，下列何者正確？', '["室內消防栓箱身應具有足夠裝設消防栓、水帶及瞄子等裝備之深度，其箱面表面積在0.7平方公尺以上", "設置第一種室內消防栓時，各層任一點至消防栓接頭之水平距離不得超過15公尺", "供集會或娛樂處所，應設於舞臺二側、觀眾席前二側、包廂後側之位置", "立管管徑，第一種消防栓不得小於50公厘；第二種消防栓不得小於63公厘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02143', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，移動放射方式之二氧化碳滅火設備，皮管接頭至防護對象任 一部分之水平距離應在多少公尺以下？', '["10", "15", "20", "25"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02144', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '福爾摩沙肥料公司，因製程需使用大量硫酸，故設置有硫酸製造原料硫磺之室外儲槽，由於其為顯著滅 火困難場所，依各類場所消防安全設備設置標準，應設置何種滅火設備？', '["第三種滅火設備之水霧滅火設備", "第一種滅火設備之室外消防栓設備", "第二種滅火設備", "第三種滅火設備之固定式泡沫滅火設備"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02145', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '某十層以下建築物，供百貨商場使用之場所，樓地板面積二千五百平方公尺，設置自動撒水設備使用密 閉式一般反應型撒水頭時，其水源容量不得小於幾個撒水頭繼續放水二十分鐘之水量？', '["十個", "十二個", "十五個", "三十個"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02146', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '某新建大樓之室內消防栓設備加壓送水裝置全閉揚程如為70 m，消防立管管系竣工時，應做加壓試驗， 試驗壓力不得小於多少之水壓？', '["7 kgf/cm2", "10.5 kgf/cm2", "14 kgf/cm2", "30 kgf/cm2"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02147', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '國光加氣站有一儲氣槽、四臺加氣機及一棟每層樓地板面積為九十六平方公尺之三層樓建築物，依各類 場所消防安全設備設置標準，該加氣站至少應設置多少個滅火器？', '["十", "十二", "十四", "十六"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02148', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '室外消防栓口徑不得小於六十三公厘，與建築物一樓外牆各部分之水平距離不得超過幾公尺？', '["15公尺", "25公尺", "30公尺", "40公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02149', 'fire-eq-tech', 'fire-eq-tech-moex-102-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '某一密閉立體機械停車空間長8公尺、寬6公尺及高10公尺，設置有二氧化碳滅火設備為採全區放射方 式時，開口可自動關閉，依各類場所消防安全設備設置標準，所需滅火藥劑量至少為何？', '["280 kg", "360 kg", "384 kg", "480 kg"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "86ea6780c6f4", "answer_pdf_sha1": "ff0cdee74800", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0710", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
